      runtime: lambda.Runtime.NODEJS_22_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset(path.join(__dirname, '../../lambda/contact')),
      role: lambdaRole,
      timeout: cdk.Duration.seconds(30),
      environment: {
        SENDER_EMAIL: `noreply@${domainName}`,
      },
    });

    // Quote Form Lambda
    const quoteLambda = new lambda.Function(this, 'QuoteLambda', {
      runtime: lambda.Runtime.NODEJS_22_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset(path.join(__dirname, '../../lambda/quote')),
      role: lambdaRole,
      timeout: cdk.Duration.seconds(30),
      environment: {
        SENDER_EMAIL: `noreply@${domainName}`,
      },
    });

    // Google Reviews Lambda
    const reviewsLambda = new lambda.Function(this, 'ReviewsLambda', {
      runtime: lambda.Runtime.NODEJS_22_X,
      handler: 'index.handler',
      code: lambda.Code.fromAsset(path.join(__dirname, '../../lambda/google-reviews')),
      timeout: cdk.Duration.seconds(30),
      environment: {
        // These will be set via AWS Console or secrets manager
        GOOGLE_MY_BUSINESS_ACCOUNT_ID: '',
        GOOGLE_MY_BUSINESS_LOCATION_ID: '',
        GOOGLE_MY_BUSINESS_API_KEY: '',
      },
    });

    // ============================================
    // API Gateway with Rate Limiting
    // ============================================

    const api = new apigateway.RestApi(this, 'SuperSolarApi', {
      restApiName: 'Super Solar Energy API',
      description: 'API for contact forms and reviews',
      defaultCorsPreflightOptions: {
        allowOrigins: apigateway.Cors.ALL_ORIGINS,
        allowMethods: apigateway.Cors.ALL_METHODS,
        allowHeaders: ['Content-Type', 'Authorization'],
      },
      deployOptions: {
        // Rate limiting: 10 requests per second, burst of 20
        throttlingRateLimit: 10,
        throttlingBurstLimit: 20,
      },
    });

    // Usage plan with stricter limits for form submissions
    const usagePlan = api.addUsagePlan('FormSubmissionPlan', {
      name: 'FormSubmissionPlan',
      description: 'Rate limiting for contact and quote forms',
      throttle: {
        rateLimit: 5,    // 5 requests per second
        burstLimit: 10,  // Allow burst of 10
      },
      quota: {
        limit: 100,      // 100 requests per day
        period: apigateway.Period.DAY,
      },
    });

    usagePlan.addApiStage({
      stage: api.deploymentStage,
    });

    // API endpoints
    const contactResource = api.root.addResource('api').addResource('contact');
    contactResource.addMethod('POST', new apigateway.LambdaIntegration(contactLambda));

    const quoteResource = api.root.getResource('api')!.addResource('quote');
    quoteResource.addMethod('POST', new apigateway.LambdaIntegration(quoteLambda));

    const reviewsResource = api.root.getResource('api')!.addResource('google-reviews');
    reviewsResource.addMethod('GET', new apigateway.LambdaIntegration(reviewsLambda));

    // ============================================
    // CloudFront
    // ============================================

    // CloudFront Function to handle subdirectory index.html rewrites
    const urlRewriteFunction = new cloudfront.Function(this, 'UrlRewriteFunction', {
      code: cloudfront.FunctionCode.fromInline(`
function handler(event) {
  var request = event.request;
  var uri = request.uri;

  // Check if URI ends with '/' and add index.html
  if (uri.endsWith('/')) {
    request.uri += 'index.html';
  }
  // Check if URI doesn't have an extension (no dot in last segment)
  else if (!uri.includes('.')) {
    request.uri += '/index.html';
  }

  return request;
}
      `),
      functionName: 'SuperSolarUrlRewrite',
      comment: 'Rewrites URLs to append index.html for subdirectories',
    });

    // Create CloudFront distribution with custom domain
    const distribution = new cloudfront.Distribution(this, 'SuperSolarDistribution', {
      defaultBehavior: {
        origin: origins.S3BucketOrigin.withOriginAccessControl(websiteBucket),
        viewerProtocolPolicy: cloudfront.ViewerProtocolPolicy.REDIRECT_TO_HTTPS,
        allowedMethods: cloudfront.AllowedMethods.ALLOW_GET_HEAD_OPTIONS,
        cachedMethods: cloudfront.CachedMethods.CACHE_GET_HEAD_OPTIONS,
        cachePolicy: cloudfront.CachePolicy.CACHING_OPTIMIZED,
        compress: true,
        functionAssociations: [{
          function: urlRewriteFunction,
          eventType: cloudfront.FunctionEventType.VIEWER_REQUEST,
        }],
      },
      domainNames: certificate ? [domainName, wwwDomainName] : undefined,
      certificate: certificate,
      defaultRootObject: 'index.html',
      errorResponses: [
        {
          httpStatus: 404,
          responseHttpStatus: 404,
          responsePagePath: '/404.html',
          ttl: cdk.Duration.minutes(5),
        },
        {
          httpStatus: 403,
          responseHttpStatus: 404,
          responsePagePath: '/404.html',
          ttl: cdk.Duration.minutes(5),
        },
      ],
      priceClass: cloudfront.PriceClass.PRICE_CLASS_100,
      minimumProtocolVersion: cloudfront.SecurityPolicyProtocol.TLS_V1_2_2021,
    });

    // Create Route53 A records only if certificate is available
    if (certificate) {
      new route53.ARecord(this, 'SuperSolarAliasRecord', {
        zone: this.hostedZone,
        recordName: domainName,
        target: route53.RecordTarget.fromAlias(new targets.CloudFrontTarget(distribution)),
      });

      new route53.ARecord(this, 'SuperSolarWwwAliasRecord', {
        zone: this.hostedZone,
        recordName: wwwDomainName,
        target: route53.RecordTarget.fromAlias(new targets.CloudFrontTarget(distribution)),
      });
    }

    // ============================================
    // Outputs
    // ============================================

    new cdk.CfnOutput(this, 'BucketName', {
      value: websiteBucket.bucketName,
      description: 'S3 Bucket Name for GitHub Actions',
      exportName: 'SuperSolarBucketName',
    });

    new cdk.CfnOutput(this, 'DistributionId', {
      value: distribution.distributionId,
      description: 'CloudFront Distribution ID for cache invalidation',
      exportName: 'SuperSolarDistributionId',
    });

    new cdk.CfnOutput(this, 'DistributionDomainName', {
      value: distribution.distributionDomainName,
      description: 'CloudFront Distribution Domain Name',
      exportName: 'SuperSolarDistributionDomain',
    });

    new cdk.CfnOutput(this, 'WebsiteURL', {
      value: certificate ? `https://${domainName}` : `https://${distribution.distributionDomainName}`,
      description: 'Website URL',
    });

    new cdk.CfnOutput(this, 'CloudFrontURL', {
      value: `https://${distribution.distributionDomainName}`,
      description: 'CloudFront Distribution URL',
    });

    new cdk.CfnOutput(this, 'ApiEndpoint', {
      value: api.url,
      description: 'API Gateway Endpoint URL',
      exportName: 'SuperSolarApiEndpoint',
    });

    new cdk.CfnOutput(this, 'HostedZoneId', {
      value: this.hostedZone.hostedZoneId,
      description: 'Route53 Hosted Zone ID',
      exportName: 'SuperSolarHostedZoneId',
    });

    new cdk.CfnOutput(this, 'HostedZoneName', {
      value: this.hostedZone.zoneName,
      description: 'Route53 Hosted Zone Name',
      exportName: 'SuperSolarHostedZoneName',
    });

    new cdk.CfnOutput(this, 'NameServers', {
      value: cdk.Fn.join(', ', this.hostedZone.hostedZoneNameServers || []),
      description: 'Route53 Name Servers - Update these at Hostinger',
    });

    new cdk.CfnOutput(this, 'DomainName', {
      value: domainName,
      description: 'Custom Domain Name',
    });

    new cdk.CfnOutput(this, 'Architecture', {
      value: 'Route53 + S3 + CloudFront + ACM + Lambda + API Gateway',
      description: 'Static site with serverless API',
    });

    new cdk.CfnOutput(this, 'CostOptimization', {
      value: 'Route53 ($0.50) + S3 + CloudFront + Lambda: ~$3-6/month',
      description: 'Expected monthly cost for low traffic',
    });

    new cdk.CfnOutput(this, 'SESNote', {
      value: 'Remember to verify email domain in SES and request production access',
      description: 'SES Setup Required',
    });
  }
}

// Super Solar Energy — Contact Form Lambda
// Receives a POST from the frontend, sends a formatted contact email via Amazon SES.

const { SESClient, SendEmailCommand } = require('@aws-sdk/client-ses');

const ses = new SESClient({ region: process.env.AWS_REGION || 'ap-southeast-2' });

const RECIPIENT_EMAIL = 'info@supersolarenergy.com.au';
const CC_EMAIL = 'manish.bvc@gmail.com';
const SENDER_EMAIL = process.env.SENDER_EMAIL || 'noreply@supersolarenergy.com.au';

const CORS_HEADERS = {
  'Content-Type': 'application/json',
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'Content-Type',
  'Access-Control-Allow-Methods': 'POST,OPTIONS',
};

exports.handler = async (event) => {
  // Handle CORS preflight
  if (event.httpMethod === 'OPTIONS') {
    return { statusCode: 200, headers: CORS_HEADERS, body: '' };
  }

  try {
    const data = JSON.parse(event.body || '{}');
    const { name, email, phone, address, service_interest, message } = data;

    if (!name || !email) {
      return {
        statusCode: 400,
        headers: CORS_HEADERS,
        body: JSON.stringify({ error: 'Name and email are required' }),
      };
    }

    const html = `<!DOCTYPE html>
<html lang="en">
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:#f4f4f5;font-family:Arial,Helvetica,sans-serif">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f5;padding:32px 16px">
    <tr><td>
      <table width="100%" cellpadding="0" cellspacing="0" style="max-width:580px;margin:0 auto;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08)">

        <!-- Header -->
        <tr>
          <td style="background:#0073b9;padding:28px 32px">
            <h1 style="margin:0;color:#ffffff;font-size:22px;font-weight:700;letter-spacing:-0.3px">New Contact Form Submission</h1>
            <p style="margin:6px 0 0;color:rgba(255,255,255,0.75);font-size:13px">Super Solar Energy &middot; supersolarenergy.com.au</p>
          </td>
        </tr>

        <!-- Contact details -->
        <tr>
          <td style="padding:28px 32px 20px">
            <h2 style="margin:0 0 16px;font-size:14px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:#0073b9">Contact Details</h2>
            <table cellpadding="0" cellspacing="0" style="width:100%">
              <tr>
                <td style="padding:5px 0;color:#888;font-size:13px;width:130px">Name</td>
                <td style="padding:5px 0;font-size:13px;font-weight:600">${escapeHtml(name)}</td>
              </tr>
              <tr>
                <td style="padding:5px 0;color:#888;font-size:13px">Email</td>
                <td style="padding:5px 0;font-size:13px;font-weight:600"><a href="mailto:${escapeHtml(email)}" style="color:#0073b9">${escapeHtml(email)}</a></td>
              </tr>
              <tr>
                <td style="padding:5px 0;color:#888;font-size:13px">Phone</td>
                <td style="padding:5px 0;font-size:13px;font-weight:600">${escapeHtml(phone || 'Not provided')}</td>
              </tr>
              <tr>
                <td style="padding:5px 0;color:#888;font-size:13px">Address</td>
                <td style="padding:5px 0;font-size:13px;font-weight:600">${escapeHtml(address || 'Not provided')}</td>
              </tr>
              <tr>
                <td style="padding:5px 0;color:#888;font-size:13px">Service Interest</td>
                <td style="padding:5px 0;font-size:13px;font-weight:600">${escapeHtml(service_interest || 'Not specified')}</td>
              </tr>
              ${message ? `<tr>
                <td style="padding:5px 0;color:#888;font-size:13px;vertical-align:top">Message</td>
                <td style="padding:5px 0;font-size:13px">${escapeHtml(message)}</td>
              </tr>` : ''}
            </table>
          </td>
        </tr>

        <!-- Footer -->
        <tr>
          <td style="background:#f9fafb;padding:16px 32px;border-top:1px solid #f0f0f0">
            <p style="margin:0;font-size:11px;color:#aaa">Submitted via supersolarenergy.com.au — Reply directly to this email to respond to the customer.</p>
          </td>
        </tr>

      </table>
    </td></tr>
  </table>
</body>
</html>`;

    const textBody = [
      'NEW CONTACT FORM SUBMISSION — SUPER SOLAR ENERGY',
      '='.repeat(50),
      '',
      'CONTACT DETAILS',
      `Name:             ${name}`,
      `Email:            ${email}`,
      `Phone:            ${phone || 'Not provided'}`,
      `Address:          ${address || 'Not provided'}`,
      `Service Interest: ${service_interest || 'Not specified'}`,
      message ? `Message:          ${message}` : '',
      '',
      'Submitted via supersolarenergy.com.au',
    ]
      .filter((l) => l !== undefined)
      .join('\n');

    await ses.send(
      new SendEmailCommand({
        Source: `Super Solar Energy <${SENDER_EMAIL}>`,
        Destination: {
          ToAddresses: [RECIPIENT_EMAIL],
          CcAddresses: [CC_EMAIL],
        },
        ReplyToAddresses: [email],
        Message: {
          Subject: {
            Data: `New Contact Form Submission from ${name}`,
            Charset: 'UTF-8',
          },
          Body: {
            Html: { Data: html, Charset: 'UTF-8' },
            Text: { Data: textBody, Charset: 'UTF-8' },
          },
        },
      })
    );

    return {
      statusCode: 200,
      headers: CORS_HEADERS,
      body: JSON.stringify({ message: 'Contact form submitted successfully' }),
    };
  } catch (error) {
    console.error('Contact Lambda error:', error);
    return {
      statusCode: 500,
      headers: CORS_HEADERS,
      body: JSON.stringify({ error: 'Failed to submit contact form. Please contact us at info@supersolarenergy.com.au' }),
    };
  }
};

function escapeHtml(str) {
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#x27;');
}

