import 'source-map-support/register';
import * as cdk from 'aws-cdk-lib';
import { WebsiteStack } from '../lib/website-stack';

const app = new cdk.App();

const account = process.env.CDK_DEFAULT_ACCOUNT || process.env.AWS_ACCOUNT_ID || '';
if (!account) {
  throw new Error('AWS account ID required. Set CDK_DEFAULT_ACCOUNT or AWS_ACCOUNT_ID.');
}

// Optional: pass CERTIFICATE_ARN secret once the cert has been created and
// nameservers have been pointed at Route53. Until then the site runs on
// the CloudFront *.cloudfront.net URL.
