  certificateArn: certificateArn,
  description: 'Super Solar Energy - Route53 + S3 + CloudFront Static Website',
  tags: {
    Project: 'SuperSolarEnergy',
    Owner: 'Manish Mitra',
    Environment: 'Production',
  },
});

app.synth();

